namespace Appraisal.Domain.Appraisals;

/// <summary>
/// Discriminator constants for AppraisalFeeItem.Source — who created the fee line.
/// "System" — generated by the system (base appraisal fee, construction-inspection fee,
///            quotation fees). Never subject to the approval flow.
/// "User"   — entered by a human via an inline edit (currently external company; future
///            internal staff). Subject to the fee-approval policy.
/// Distinct from RequestSource (Ext/Int), which is the channel that raises the approval —
/// this is who authored the line item.
/// </summary>
public static class FeeItemSource
{
    public const string System = "System";
    public const string User = "User";
}

/// <summary>
/// Individual fee line item within an AppraisalFee.
/// Supports approval workflow for additional fees.
/// </summary>
public class AppraisalFeeItem : Entity<Guid>
{
    public Guid AppraisalFeeId { get; private set; }

    // Fee Details
    public string FeeCode { get; private set; } = null!; // 01=AppraisalFee, 02=Travel, 03=Urgent
    public string FeeDescription { get; private set; } = null!;
    public decimal FeeAmount { get; private set; }

    // Approval (for additional fees)
    public bool RequiresApproval { get; private set; }
    public string? ApprovalStatus { get; private set; } // Pending, Approved, Rejected
    public Guid? ApprovedBy { get; private set; }
    public DateTime? ApprovedAt { get; private set; }
    public string? RejectionReason { get; private set; }

    /// <summary>
    /// Stamped when Submit for Approval is called on the parent fee.
    /// Null means this item is a draft not yet submitted for bank review.
    /// </summary>
    public DateTime? ApprovalSubmittedAt { get; private set; }

    /// <summary>
    /// Who created this fee line — <see cref="FeeItemSource"/> ("System" | "User").
    /// "User" only for items entered via the inline-edit path (AddFeeItemCommandHandler);
    /// "System" (default) for the base appraisal fee, construction-inspection fee, and any
    /// other system-created items. This is the authoritative filter for ReevaluateAddedFees
    /// and the cumulative-total computation — only "User" items are subject to approval.
    /// </summary>
    public string Source { get; private set; } = FeeItemSource.System;

    /// <summary>
    /// A user-entered fee in a non-final approval state (draft or pending). These are the only
    /// items ReevaluateAddedFees flips and that count toward the cumulative approval total.
    /// Excludes System fees and finalised (Approved/Rejected) items.
    /// </summary>
    public bool IsActiveAddedFee =>
        Source == FeeItemSource.User && (ApprovalStatus is null || ApprovalStatus == "Pending");

    /// <summary>
    /// True once the approval outcome is final (Approved or Rejected). The amount must not change.
    /// </summary>
    public bool IsFinalised => ApprovalStatus is "Approved" or "Rejected";

    private AppraisalFeeItem()
    {
        // For EF Core
    }

    public static AppraisalFeeItem Create(
        Guid appraisalFeeId,
        string feeCode,
        string feeDescription,
        decimal feeAmount,
        bool requiresApproval = false)
    {
        return new AppraisalFeeItem
        {
            //Id = Guid.CreateVersion7(),
            AppraisalFeeId = appraisalFeeId,
            FeeCode = feeCode,
            FeeDescription = feeDescription,
            FeeAmount = feeAmount,
            RequiresApproval = requiresApproval,
            ApprovalStatus = requiresApproval ? "Pending" : null
        };
    }

    public void Update(string feeCode, string feeDescription, decimal feeAmount)
    {
        FeeCode = feeCode;
        FeeDescription = feeDescription;
        FeeAmount = feeAmount;
    }

    /// <summary>
    /// Marks this item as user-entered (Source = "User"). Called once, immediately after
    /// creation, only by the inline AddFeeItemCommandHandler. Never called for base or
    /// system-created items, which keep the default Source = "System".
    /// </summary>
    public void MarkAsUserAdded()
    {
        Source = FeeItemSource.User;
    }

    /// <summary>
    /// Stamps ApprovalSubmittedAt to record that this item has been submitted for bank review.
    /// </summary>
    public void MarkApprovalSubmitted()
    {
        ApprovalSubmittedAt = DateTime.Now;
    }

    /// <summary>
    /// Flips this item to the billable state: clears RequiresApproval and ApprovalStatus.
    /// Used by ReevaluateAddedFees when the policy verdict is "no approval needed".
    /// </summary>
    public void MakeBillable()
    {
        RequiresApproval = false;
        ApprovalStatus = null;
        ApprovalSubmittedAt = null;
    }

    /// <summary>
    /// Flips this item to the pending-approval state.
    /// Used by ReevaluateAddedFees when the policy verdict is "approval needed".
    /// </summary>
    public void MakePendingApproval()
    {
        RequiresApproval = true;
        ApprovalStatus = "Pending";
        ApprovalSubmittedAt = null;
    }

    /// <summary>
    /// Clears approval markers after a resolution so a fresh draft can begin.
    /// </summary>
    public void ClearApprovalMarkers()
    {
        RequiresApproval = false;
        ApprovalStatus = null;
        ApprovalSubmittedAt = null;
    }

    public void Approve(Guid approvedBy)
    {
        if (ApprovalStatus != "Pending")
            throw new InvalidOperationException($"Cannot approve fee item in status '{ApprovalStatus}'");

        ApprovalStatus = "Approved";
        ApprovedBy = approvedBy;
        ApprovedAt = DateTime.Now;
        // Clear the draft markers so the FE "awaiting approval" badge/banner clears.
        // ApprovalStatus stays "Approved" so RecalculateFromItems() counts this item as billable.
        RequiresApproval = false;
        ApprovalSubmittedAt = null;
    }

    public void Reject(Guid rejectedBy, string reason)
    {
        if (ApprovalStatus != "Pending")
            throw new InvalidOperationException($"Cannot reject fee item in status '{ApprovalStatus}'");

        ApprovalStatus = "Rejected";
        ApprovedBy = rejectedBy;
        ApprovedAt = DateTime.Now;
        RejectionReason = reason;
        // Clear the submitted marker so the FE "awaiting approval" badge clears and shows
        // "Rejected" instead. RequiresApproval stays true so the rejected fee is excluded from
        // the billable total (RecalculateFromItems counts only !RequiresApproval || Approved).
        ApprovalSubmittedAt = null;
    }
}